class Playground {
    async run(inputs) {
        const words = inputs[0].split(',').map(w => w.trim());
        const k = parseInt(inputs[1]);

        this.wordsArray.init(words);
        this.frequencyMap.init([]);
        this.minHeap.init([], 'min', 'freq');
        this.state.init([]);

        this.state.put('k', k);
        this.log('Initialized input and variables');
        await this.await();

        // Step 1: Build Frequency Map
        for (let i = 0; i < words.length; i++) {
            const word = words[i];
            this.wordsArray.highlight(i, '#ffb703');
            this.log('Processing word: ' + word);
            await this.await();

            let count = 0;
            if (this.frequencyMap.has(word)) {
                count = this.frequencyMap.get(word);
            }
            this.frequencyMap.put(word, count + 1);
            this.frequencyMap.highlight(word, '#00e0ff');
            this.log('Updated frequency of ' + word + ' to ' + (count + 1));
            await this.await();
        }

        this.log('Frequency map constructed. Now building Min Heap of size k');
        await this.await();

        // Step 2: Build Min Heap of size k
        const entries = this.frequencyMap.getEntries();
        for (let i = 0; i < entries.length; i++) {
            const word = entries[i][0];
            const freq = entries[i][1];

            const node = { word: word, freq: freq };
            this.minHeap.push(node);
            this.log('Inserted into heap: ' + word + ' with freq ' + freq);
            await this.await();

            if (this.minHeap.size() > k) {
                const removed = this.minHeap.pop();
                this.log('Heap size exceeded k. Removed: ' + removed.word);
                await this.await();
            }
        }

        this.log('Heap constructed. Extracting top k elements');
        await this.await();

        // Step 3: Extract elements
        const result = [];
        while (!this.minHeap.isEmpty()) {
            const node = this.minHeap.pop();
            result.push(node.word);
            this.log('Extracted: ' + node.word);
            await this.await();
        }

        result.reverse();
        this.log('Final result after reversing: ' + JSON.stringify(result));
        await this.await();

        return result;
    }
}
